{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 조건으로 금요일 15:00 KST 공개 릴리스를 목표로 한다.",
        "acceptance_gate": "스모크 테스트 통과"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName mismatch 발생 시 먼저 패키지 설정(계약) 확인, 계약 자체가 잘못된 경우에만 스크립트 검토"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표(확정 공개 일정 아님)"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 검토 제안 있었으나 소유자 미지정"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스 지연 가능"
      },
      {
        "risk": "README 설치 단계가 오래되었을 경우 릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "미해결"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "status": "미해결"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 확인",
      "due": "미정",
      "status": "확정(기한 미정)",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(가능 시)",
      "status": "제안",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "next_checks": [
      "스모크 테스트 통과 여부 확인(공개 릴리스 게이트)",
      "Minjun 결과 공유 후 tarball 경로 검증 완료 여부 확인",
      "Doyun의 failure triage note 작성 완료 확인",
      "README 설치 단계 최신성 점검 주체 지정 필요",
      "최종 릴리스 승인 권한자 확정 필요",
      "릴리스 노트에 수요일 스트레치 목표 언급 여부 결정 필요"
    ],
    "do_not_invent": [
      "고객/외부 파트너 정보",
      "예산 수치 또는 승인",
      "보안 사고 사실",
      "프로덕션 장애 사실",
      "법무 승인 요구사항",
      "미지정 owner",
      "미합의 deadline"
    ]
  },
  "non_invention_rules": {
    "scope_rule": "인라인 픽스처에 명시된 사실만 사용",
    "fact_boundary": [
      "확정/반려/제안/미해결을 구분해 기록",
      "명시되지 않은 소유자·기한·승인체계는 추정 금지",
      "고객·예산·보안·장애·법무 관련 사실 추가 금지"
    ],
    "labeling_rule": "불확실 항목은 tentative 또는 미해결로 표시"
  }
}
